  if (!response) {
    response = await fetch(request)
    // Cache the fetched response for custom TTL
    if (response.ok) {
      event.waitUntil(cache.put(cacheKey, response.clone()))
    }
  }

  return new Response(response.body, {
    ...response,
    headers: {
      ...response.headers,
      'Cache-Control': `max-age=${cacheTTL}`
    }
  })
